request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?traceStart ?traceStartName ?analysis ?analysisName ?depRel WHERE {
  ?traceStart vocab:NamedElement_name ?traceStartName .
  FILTER(
    CONTAINS(LCASE(STR(?traceStartName)), LCASE("high")) &&
    (CONTAINS(LCASE(STR(?traceStartName)), LCASE("exposure")) ||
     CONTAINS(LCASE(STR(?traceStartName)), LCASE("exposures")) ||
     CONTAINS(LCASE(STR(?traceStartName)), LCASE("apt exposure")))
  )
  ?traceStart rdf:type ?traceStartType .

  ?analysis rdf:type ?analysisType .
  ?analysis vocab:NamedElement_name ?analysisName .

  {
    ?depRel rdf:type vocab:dependency .
    ?depRel vocab:Dependency_client ?analysis .
    ?depRel vocab:Dependency_supplier ?traceStart .
  } UNION {
    ?depRel rdf:type vocab:satisfy .
    ?depRel vocab:Dependency_client ?analysis .
    ?depRel vocab:Dependency_supplier ?traceStart .
  } UNION {
    ?depRel rdf:type vocab:verify .
    ?depRel vocab:Dependency_client ?analysis .
    ?depRel vocab:Dependency_supplier ?traceStart .
  }
}
LIMIT 25
